chart.options:
chart: {
  type: 'bar',
  height: 350,
  stacked: true,
  toolbar: {
    show: true,
  },
},
stroke: {
  width: 1,
  colors: ['#fff'],
},
plotOptions: {
  bar: {
    horizontal: false,
    borderRadius: 10,
    borderRadiusApplication: 'end',
    borderRadiusWhenStacked: 'last',
    dataLabels: {
      total: {
        enabled: true,
        style: {
          fontSize: '13px',
          fontWeight: 900,
        },
      },
    },
  },
},
title: {
  text: 'Quarterly Profit & Loss by Segment',
  align: 'left',
},
xaxis: {
  categories: ['Q1 2024', 'Q2 2024', 'Q3 2024', 'Q4 2024', 'Q1 2025', 'Q2 2025'],
},
yaxis: {
  labels: {
    formatter: function (val) {
      return '$' + val + 'M'
    }
  }
},
legend: {
  position: 'right',
  offsetY: 40,
},
fill: {
  opacity: 1,
}
